@namespace sv_21cb796d98ee4798a653876930a9c328.Components.Pages.Settings

<nav class="nav nav-pills flex-column settings-sidebar">
    @foreach (var section in Sections)
    {
        <button class="nav-link text-start @(section == ActiveSection ? "active" : "")"
                @onclick="() => OnSectionSelected.InvokeAsync(section)">
            <span class="me-2">@GetIcon(section)</span>@section
        </button>
    }
</nav>

@code {
    [Parameter] public string ActiveSection { get; set; } = "Profile";
    [Parameter] public EventCallback<string> OnSectionSelected { get; set; }

    private static readonly string[] Sections = ["Profile", "Notifications", "Security", "Appearance"];

    private static string GetIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };
}

@namespace sv_21cb796d98ee4798a653876930a9c328.Components.Pages.Settings
@using sv_21cb796d98ee4798a653876930a9c328.Services

<div class="profile-section">
    <h4 class="mb-4">Profile Settings</h4>

    @if (Profile is null)
    {
        <p class="text-muted">Loading...</p>
        return;
    }

    <div class="row">
        <div class="col-md-8">
            <div class="mb-3">
                <label class="form-label fw-semibold">Display Name</label>
                <input type="text" class="form-control" @bind="DisplayName" />
            </div>
            <div class="mb-3">
                <label class="form-label fw-semibold">Email</label>
                <input type="email" class="form-control" @bind="Email" />
            </div>
            <div class="mb-3">
                <label class="form-label fw-semibold">Bio</label>
                <textarea class="form-control" rows="4" @bind="Bio"></textarea>
            </div>
        </div>
        <div class="col-md-4 text-center">
            <div class="mb-2">
                <img src="@AvatarUrl" alt="Avatar" class="rounded-circle border" style="width:120px;height:120px;object-fit:cover;" />
            </div>
            <div class="text-muted small text-break">@AvatarUrl</div>
        </div>
    </div>

    <div class="d-flex gap-2 mt-3">
        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@IsSaving">
            @if (IsSaving) { <span class="spinner-border spinner-border-sm me-1"></span> }
            Save Changes
        </button>
        <button class="btn btn-outline-secondary" @onclick="Discard" disabled="@IsSaving">
            Discard Changes
        </button>
    </div>

    @if (ShowSuccess)
    {
        <div class="alert alert-success mt-3 fade show" role="alert">
            ✅ Profile saved successfully!
        </div>
    }
</div>

@code {
    [Parameter] public UserProfile? Profile { get; set; }
    [Parameter] public EventCallback<UserProfile> OnSave { get; set; }

    private string DisplayName = "";
    private string Email = "";
    private string AvatarUrl = "";
    private string Bio = "";
    private bool IsSaving;
    private bool ShowSuccess;

    protected override void OnParametersSet()
    {
        if (Profile is not null && !_initialized)
        {
            ResetFields();
            _initialized = true;
        }
    }

    private bool _initialized;

    private void ResetFields()
    {
        if (Profile is null) return;
        DisplayName = Profile.DisplayName;
        Email = Profile.Email;
        AvatarUrl = Profile.AvatarUrl;
        Bio = Profile.Bio;
    }

    private async Task SaveAsync()
    {
        IsSaving = true;
        ShowSuccess = false;
        var updated = new UserProfile(DisplayName, Email, AvatarUrl, Bio);
        await OnSave.InvokeAsync(updated);
        IsSaving = false;
        ShowSuccess = true;
        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        ShowSuccess = false;
        await InvokeAsync(StateHasChanged);
    }

    private void Discard()
    {
        ResetFields();
        ShowSuccess = false;
    }
}

@namespace sv_21cb796d98ee4798a653876930a9c328.Components.Pages.Settings
@using sv_21cb796d98ee4798a653876930a9c328.Services

<div class="notifications-section">
    <h4 class="mb-4">Notification Preferences</h4>

    @if (Prefs is null)
    {
        <p class="text-muted">Loading...</p>
        return;
    }

    <div class="mb-4">
        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="emailNotif" checked="@EmailNotifications" @onchange="e => EmailNotifications = (bool)e.Value!" />
            <label class="form-check-label" for="emailNotif">Email Notifications</label>
        </div>
        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="pushNotif" checked="@PushNotifications" @onchange="e => PushNotifications = (bool)e.Value!" />
            <label class="form-check-label" for="pushNotif">Push Notifications</label>
        </div>
        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="weeklyDigest" checked="@WeeklyDigest" @onchange="e => WeeklyDigest = (bool)e.Value!" />
            <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
        </div>
    </div>

    <h5 class="mb-3">Muted Channels</h5>
    <div class="mb-4">
        @foreach (var channel in AvailableChannels)
        {
            <div class="form-check mb-2">
                <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                       checked="@MutedChannels.Contains(channel)"
                       @onchange="e => ToggleChannel(channel, (bool)e.Value!)" />
                <label class="form-check-label" for="@($"ch-{channel}")">@channel</label>
            </div>
        }
    </div>

    <button class="btn btn-primary" @onclick="SaveAsync" disabled="@IsSaving">
        @if (IsSaving) { <span class="spinner-border spinner-border-sm me-1"></span> }
        Save Preferences
    </button>

    @if (ShowSuccess)
    {
        <div class="alert alert-success mt-3 fade show" role="alert">
            ✅ Notification preferences saved!
        </div>
    }
</div>

@code {
    [Parameter] public NotificationPrefs? Prefs { get; set; }
    [Parameter] public EventCallback<NotificationPrefs> OnSave { get; set; }

    private bool EmailNotifications;
    private bool PushNotifications;
    private bool WeeklyDigest;
    private List<string> MutedChannels = [];
    private bool IsSaving;
    private bool ShowSuccess;
    private bool _initialized;

    private static readonly string[] AvailableChannels = ["general", "announcements", "marketing", "engineering", "support"];

    protected override void OnParametersSet()
    {
        if (Prefs is not null && !_initialized)
        {
            EmailNotifications = Prefs.EmailNotifications;
            PushNotifications = Prefs.PushNotifications;
            WeeklyDigest = Prefs.WeeklyDigest;
            MutedChannels = [..Prefs.MutedChannels];
            _initialized = true;
        }
    }

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted && !MutedChannels.Contains(channel))
            MutedChannels.Add(channel);
        else if (!muted)
            MutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        IsSaving = true;
        ShowSuccess = false;
        var updated = new NotificationPrefs(EmailNotifications, PushNotifications, WeeklyDigest, [..MutedChannels]);
        await OnSave.InvokeAsync(updated);
        IsSaving = false;
        ShowSuccess = true;
        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        ShowSuccess = false;
        await InvokeAsync(StateHasChanged);
    }
}

@namespace sv_21cb796d98ee4798a653876930a9c328.Components.Pages.Settings

<div class="card mb-4">
    <div class="card-header d-flex justify-content-between align-items-center"
         style="cursor:pointer" @onclick="() => IsExpanded = !IsExpanded">
        <span class="fw-semibold">🔑 Change Password</span>
        <span>@(IsExpanded ? "▲" : "▼")</span>
    </div>
    @if (IsExpanded)
    {
        <div class="card-body">
            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="CurrentPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="NewPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="ConfirmPassword" />
            </div>

            @if (!string.IsNullOrEmpty(ErrorMessage))
            {
                <div class="alert alert-danger">@ErrorMessage</div>
            }
            @if (ShowSuccess)
            {
                <div class="alert alert-success">✅ Password updated successfully!</div>
            }

            <button class="btn btn-warning" @onclick="UpdatePasswordAsync" disabled="@IsUpdating">
                @if (IsUpdating) { <span class="spinner-border spinner-border-sm me-1"></span> }
                Update Password
            </button>
        </div>
    }
</div>

@code {
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }

    private bool IsExpanded;
    private string CurrentPassword = "";
    private string NewPassword = "";
    private string ConfirmPassword = "";
    private string? ErrorMessage;
    private bool IsUpdating;
    private bool ShowSuccess;

    private async Task UpdatePasswordAsync()
    {
        ErrorMessage = null;
        ShowSuccess = false;

        if (string.IsNullOrWhiteSpace(CurrentPassword) || string.IsNullOrWhiteSpace(NewPassword))
        {
            ErrorMessage = "All password fields are required.";
            return;
        }
        if (NewPassword != ConfirmPassword)
        {
            ErrorMessage = "New password and confirmation do not match.";
            return;
        }
        if (NewPassword.Length < 8)
        {
            ErrorMessage = "New password must be at least 8 characters.";
            return;
        }

        IsUpdating = true;
        await OnChangePassword.InvokeAsync((CurrentPassword, NewPassword));
        IsUpdating = false;
        ShowSuccess = true;
        CurrentPassword = "";
        NewPassword = "";
        ConfirmPassword = "";
    }
}

@namespace sv_21cb796d98ee4798a653876930a9c328.Components.Pages.Settings
@using sv_21cb796d98ee4798a653876930a9c328.Services

<div class="card">
    <div class="card-header fw-semibold">📱 Active Sessions</div>
    <div class="card-body p-0">
        <div class="table-responsive">
            <table class="table table-hover mb-0">
                <thead class="table-light">
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var session in Sessions)
                    {
                        <tr>
                            <td>@session.Device</td>
                            <td>@session.Location</td>
                            <td>@FormatLastActive(session.LastActive)</td>
                            <td>
                                @if (session.Id != CurrentSessionId)
                                {
                                    <button class="btn btn-outline-danger btn-sm"
                                            @onclick="() => RequestRevoke(session)">
                                        Revoke
                                    </button>
                                }
                                else
                                {
                                    <span class="badge bg-success">Current</span>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    </div>
</div>

@* Revoke confirmation dialog *@
@if (SessionToRevoke is not null)
{
    <div class="modal d-block" tabindex="-1" style="background-color:rgba(0,0,0,0.5)">
        <div class="modal-dialog modal-dialog-centered">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                </div>
                <div class="modal-body">
                    <p>Are you sure you want to revoke the session on <strong>@SessionToRevoke.Device</strong> from <strong>@SessionToRevoke.Location</strong>?</p>
                </div>
                <div class="modal-footer">
                    <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                    <button class="btn btn-danger" @onclick="ConfirmRevokeAsync" disabled="@IsRevoking">
                        @if (IsRevoking) { <span class="spinner-border spinner-border-sm me-1"></span> }
                        Revoke
                    </button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public List<ActiveSession> Sessions { get; set; } = [];
    [Parameter] public string CurrentSessionId { get; set; } = "sess-1";
    [Parameter] public EventCallback<string> OnRevoke { get; set; }

    private ActiveSession? SessionToRevoke;
    private bool IsRevoking;

    private void RequestRevoke(ActiveSession session) => SessionToRevoke = session;
    private void CancelRevoke() => SessionToRevoke = null;

    private async Task ConfirmRevokeAsync()
    {
        if (SessionToRevoke is null) return;
        IsRevoking = true;
        await OnRevoke.InvokeAsync(SessionToRevoke.Id);
        IsRevoking = false;
        SessionToRevoke = null;
    }

    private static string FormatLastActive(DateTime lastActive)
    {
        var diff = DateTime.UtcNow - lastActive;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

@namespace sv_21cb796d98ee4798a653876930a9c328.Components.Pages.Settings
@using sv_21cb796d98ee4798a653876930a9c328.Services

<div class="security-section">
    <h4 class="mb-4">Security Settings</h4>

    @if (Settings is null)
    {
        <p class="text-muted">Loading...</p>
        return;
    }

    <ChangePasswordPanel OnChangePassword="HandleChangePassword" />

    <div class="card mb-4">
        <div class="card-body d-flex justify-content-between align-items-center">
            <div>
                <span class="fw-semibold">🛡️ Two-Factor Authentication</span>
                <br />
                <small class="text-muted">
                    @if (Settings.TwoFactorEnabled)
                    {
                        <span class="text-success">● Enabled</span>
                    }
                    else
                    {
                        <span class="text-danger">● Disabled</span>
                    }
                </small>
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" checked="@TwoFactorEnabled"
                       @onchange="e => ToggleTwoFactor((bool)e.Value!)" />
            </div>
        </div>
    </div>

    @if (Settings.LastPasswordChange.HasValue)
    {
        <p class="text-muted small mb-4">
            Last password change: @Settings.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
        </p>
    }

    <ActiveSessionsTable Sessions="Settings.Sessions" OnRevoke="HandleRevoke" />
</div>

@code {
    [Parameter] public SecuritySettings? Settings { get; set; }
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }
    [Parameter] public EventCallback<string> OnRevokeSession { get; set; }
    [Parameter] public EventCallback<bool> OnToggleTwoFactor { get; set; }

    private bool TwoFactorEnabled;
    private bool _initialized;

    protected override void OnParametersSet()
    {
        if (Settings is not null && !_initialized)
        {
            TwoFactorEnabled = Settings.TwoFactorEnabled;
            _initialized = true;
        }
    }

    private async Task HandleChangePassword((string Current, string New) args)
    {
        await OnChangePassword.InvokeAsync(args);
    }

    private async Task HandleRevoke(string sessionId)
    {
        await OnRevokeSession.InvokeAsync(sessionId);
    }

    private async Task ToggleTwoFactor(bool enabled)
    {
        TwoFactorEnabled = enabled;
        await OnToggleTwoFactor.InvokeAsync(enabled);
    }
}

@namespace sv_21cb796d98ee4798a653876930a9c328.Components.Pages.Settings
@using sv_21cb796d98ee4798a653876930a9c328.Services

<div class="card">
    <div class="card-header fw-semibold">👁️ Live Preview</div>
    <div class="card-body" style="@PreviewStyle">
        <h5>Preview</h5>
        <p>This is how your content will look with the selected settings.</p>
        <button class="btn @ButtonClass btn-sm">Sample Button</button>
        <span class="badge @BadgeClass ms-2">Badge</span>
    </div>
</div>

@code {
    [Parameter] public string Theme { get; set; } = "Light";
    [Parameter] public string FontSize { get; set; } = "Medium";
    [Parameter] public bool CompactMode { get; set; }

    private string PreviewStyle
    {
        get
        {
            var bg = Theme switch
            {
                "Dark" => "background-color:#1e1e1e;color:#d4d4d4;",
                "System" => "background-color:#f0f0f0;color:#333;",
                _ => "background-color:#ffffff;color:#212529;"
            };
            var fs = FontSize switch
            {
                "Small" => "font-size:0.85rem;",
                "Large" => "font-size:1.15rem;",
                _ => "font-size:1rem;"
            };
            var padding = CompactMode ? "padding:0.5rem;" : "padding:1.25rem;";
            return $"{bg}{fs}{padding}border-radius:0.375rem;";
        }
    }

    private string ButtonClass => Theme == "Dark" ? "btn-light" : "btn-primary";
    private string BadgeClass => Theme == "Dark" ? "bg-light text-dark" : "bg-primary";
}

@namespace sv_21cb796d98ee4798a653876930a9c328.Components.Pages.Settings
@using sv_21cb796d98ee4798a653876930a9c328.Services

<div class="appearance-section">
    <h4 class="mb-4">Appearance Settings</h4>

    @if (Settings is null)
    {
        <p class="text-muted">Loading...</p>
        return;
    }

    <div class="row">
        <div class="col-md-6">
            <div class="mb-4">
