<div class="card mb-4">
    <div class="card-header d-flex justify-content-between align-items-center"
         style="cursor:pointer" @onclick="() => IsExpanded = !IsExpanded">
        <span class="fw-semibold">🔑 Change Password</span>
        <span>@(IsExpanded ? "▲" : "▼")</span>
    </div>
    @if (IsExpanded)
    {
        <div class="card-body">
            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="CurrentPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="NewPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="ConfirmPassword" />
            </div>

            @if (!string.IsNullOrEmpty(ErrorMessage))
            {
                <div class="alert alert-danger">@ErrorMessage</div>
            }
            @if (ShowSuccess)
            {
                <div class="alert alert-success">✅ Password updated successfully!</div>
            }

            <button class="btn btn-warning" @onclick="UpdatePasswordAsync" disabled="@IsUpdating">
                @if (IsUpdating) { <span class="spinner-border spinner-border-sm me-1"></span> }
                Update Password
            </button>
        </div>
    }
</div>

@code {
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }

    private bool IsExpanded;
    private string CurrentPassword = "";
    private string NewPassword = "";
    private string ConfirmPassword = "";
    private string? ErrorMessage;
    private bool IsUpdating;
    private bool ShowSuccess;

    private async Task UpdatePasswordAsync()
    {
        ErrorMessage = null;
        ShowSuccess = false;

        if (string.IsNullOrWhiteSpace(CurrentPassword) || string.IsNullOrWhiteSpace(NewPassword))
        {
            ErrorMessage = "All password fields are required.";
            return;
        }
        if (NewPassword != ConfirmPassword)
        {
            ErrorMessage = "New password and confirmation do not match.";
            return;
        }
        if (NewPassword.Length < 8)
        {
            ErrorMessage = "New password must be at least 8 characters.";
            return;
        }

        IsUpdating = true;
        await OnChangePassword.InvokeAsync((CurrentPassword, NewPassword));
        IsUpdating = false;
        ShowSuccess = true;
        CurrentPassword = "";
        NewPassword = "";
        ConfirmPassword = "";
    }
}
