@namespace sv_21cb796d98ee4798a653876930a9c328.Components.Pages.Settings
@using sv_21cb796d98ee4798a653876930a9c328.Services

<div class="security-section">
    <h4 class="mb-4">Security Settings</h4>

    @if (Settings is null)
    {
        <p class="text-muted">Loading...</p>
        return;
    }

    <ChangePasswordPanel OnChangePassword="HandleChangePassword" />

    <div class="card mb-4">
        <div class="card-body d-flex justify-content-between align-items-center">
            <div>
                <span class="fw-semibold">🛡️ Two-Factor Authentication</span>
                <br />
                <small class="text-muted">
                    @if (Settings.TwoFactorEnabled)
                    {
                        <span class="text-success">● Enabled</span>
                    }
                    else
                    {
                        <span class="text-danger">● Disabled</span>
                    }
                </small>
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" checked="@TwoFactorEnabled"
                       @onchange="e => ToggleTwoFactor((bool)e.Value!)" />
            </div>
        </div>
    </div>

    @if (Settings.LastPasswordChange.HasValue)
    {
        <p class="text-muted small mb-4">
            Last password change: @Settings.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
        </p>
    }

    <ActiveSessionsTable Sessions="Settings.Sessions" OnRevoke="HandleRevoke" />
</div>

@code {
    [Parameter] public SecuritySettings? Settings { get; set; }
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }
    [Parameter] public EventCallback<string> OnRevokeSession { get; set; }
    [Parameter] public EventCallback<bool> OnToggleTwoFactor { get; set; }

    private bool TwoFactorEnabled;
    private bool _initialized;

    protected override void OnParametersSet()
    {
        if (Settings is not null && !_initialized)
        {
            TwoFactorEnabled = Settings.TwoFactorEnabled;
            _initialized = true;
        }
    }

    private async Task HandleChangePassword((string Current, string New) args)
    {
        await OnChangePassword.InvokeAsync(args);
    }

    private async Task HandleRevoke(string sessionId)
    {
        await OnRevokeSession.InvokeAsync(sessionId);
    }

    private async Task ToggleTwoFactor(bool enabled)
    {
        TwoFactorEnabled = enabled;
        await OnToggleTwoFactor.InvokeAsync(enabled);
    }
}

