@namespace sv_21cb796d98ee4798a653876930a9c328.Components.Pages.Settings
@using sv_21cb796d98ee4798a653876930a9c328.Services

<div class="card">
    <div class="card-header fw-semibold">👁️ Live Preview</div>
    <div class="card-body" style="@PreviewStyle">
        <h5>Preview</h5>
        <p>This is how your content will look with the selected settings.</p>
        <button class="btn @ButtonClass btn-sm">Sample Button</button>
        <span class="badge @BadgeClass ms-2">Badge</span>
    </div>
</div>

@code {
    [Parameter] public string Theme { get; set; } = "Light";
    [Parameter] public string FontSize { get; set; } = "Medium";
    [Parameter] public bool CompactMode { get; set; }

    private string PreviewStyle
    {
        get
        {
            var bg = Theme switch
            {
                "Dark" => "background-color:#1e1e1e;color:#d4d4d4;",
                "System" => "background-color:#f0f0f0;color:#333;",
                _ => "background-color:#ffffff;color:#212529;"
            };
            var fs = FontSize switch
            {
                "Small" => "font-size:0.85rem;",
                "Large" => "font-size:1.15rem;",
                _ => "font-size:1rem;"
            };
            var padding = CompactMode ? "padding:0.5rem;" : "padding:1.25rem;";
            return $"{bg}{fs}{padding}border-radius:0.375rem;";
        }
    }

    private string ButtonClass => Theme == "Dark" ? "btn-light" : "btn-primary";
    private string BadgeClass => Theme == "Dark" ? "bg-light text-dark" : "bg-primary";
}

