@namespace sv_21cb796d98ee4798a653876930a9c328.Components.Pages.Settings
@using sv_21cb796d98ee4798a653876930a9c328.Services

<div class="appearance-section">
    <h4 class="mb-4">Appearance Settings</h4>

    @if (Settings is null)
    {
        <p class="text-muted">Loading...</p>
        return;
    }

    <div class="row">
        <div class="col-md-6">
            <div class="mb-4">
                <label class="form-label fw-semibold">Theme</label>
                <div>
                    @foreach (var theme in new[] { "Light", "Dark", "System" })
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="theme"
                                   id="@($"theme-{theme}")" value="@theme"
                                   checked="@(Theme == theme)"
                                   @onchange="() => Theme = theme" />
                            <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                        </div>
                    }
                </div>
            </div>

            <div class="mb-4">
                <label class="form-label fw-semibold">Font Size</label>
                <div>
                    @foreach (var size in new[] { "Small", "Medium", "Large" })
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="fontSize"
                                   id="@($"fs-{size}")" value="@size"
                                   checked="@(FontSize == size)"
                                   @onchange="() => FontSize = size" />
                            <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                        </div>
                    }
                </div>
            </div>

            <div class="mb-4">
                <label class="form-label fw-semibold">Language</label>
                <select class="form-select" @bind="Language">
                    @foreach (var lang in Languages)
                    {
                        <option value="@lang">@lang</option>
                    }
                </select>
            </div>

            <div class="mb-4">
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="compactMode"
                           checked="@CompactMode"
                           @onchange="e => CompactMode = (bool)e.Value!" />
                    <label class="form-check-label" for="compactMode">Compact Mode</label>
                </div>
            </div>

            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@IsSaving">
                @if (IsSaving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                Save
            </button>

            @if (ShowSuccess)
            {
                <div class="alert alert-success mt-3 fade show" role="alert">
                    ✅ Appearance settings saved!
                </div>
            }
        </div>

        <div class="col-md-6">
            <AppearancePreview Theme="@Theme" FontSize="@FontSize" CompactMode="@CompactMode" />
        </div>
    </div>
</div>

@code {
    [Parameter] public AppearanceSettings? Settings { get; set; }
    [Parameter] public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string Theme = "Light";
    private string FontSize = "Medium";
    private string Language = "English";
    private bool CompactMode;
    private bool IsSaving;
    private bool ShowSuccess;
    private bool _initialized;

    private static readonly string[] Languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese", "Portuguese"];

    protected override void OnParametersSet()
    {
        if (Settings is not null && !_initialized)
        {
            Theme = Settings.Theme;
            FontSize = Settings.FontSize;
            Language = Settings.Language;
            CompactMode = Settings.CompactMode;
            _initialized = true;
        }
    }

    private async Task SaveAsync()
    {
        IsSaving = true;
        ShowSuccess = false;
        var updated = new AppearanceSettings(Theme, FontSize, Language, CompactMode);
        await OnSave.InvokeAsync(updated);
        IsSaving = false;
        ShowSuccess = true;
        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        ShowSuccess = false;
        await InvokeAsync(StateHasChanged);
    }
}

