@page "/settings"
@namespace sv_21cb796d98ee4798a653876930a9c328.Components.Pages.Settings
@using sv_21cb796d98ee4798a653876930a9c328.Services
@rendermode InteractiveServer
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="container-fluid py-4">
    <h2 class="mb-4">⚙️ Settings</h2>
    <div class="row">
        <div class="col-md-3 col-lg-2 mb-3">
            <SettingsSidebar ActiveSection="@ActiveSection" OnSectionSelected="SelectSection" />
        </div>
        <div class="col-md-9 col-lg-10">
            <div class="card">
                <div class="card-body">
                    @switch (ActiveSection)
                    {
                        case "Profile":
                            <ProfileSection Profile="@_profile" OnSave="SaveProfileAsync" />
                            break;
                        case "Notifications":
